const payload = JSON.parse($json.payload || '{}');

const files = [];
if ($binary) {
  for (const [key, bin] of Object.entries($binary)) {
    files.push({
      fileName: bin.fileName || key,
      contentType: bin.mimeType,
      category: key,
      contentBase64: bin.data,
    });
  }
}

return [{
  json: {
    Title: 'Trade-in Claim',
    DealerNo: payload?.dealer?.dealerNo || '',
    CompanyName: payload?.dealer?.companyName || '',
    PostalLocation: payload?.dealer?.postalLocation || '',
    Email: payload?.dealer?.email || '',
    SoldModel: payload?.product?.soldModel || '',
    NewSerialNumber: payload?.product?.newSerialNumber || '',
    TradeInType: payload?.product?.tradeInType || '',
    TradeInSerialNumber: payload?.product?.tradeInSerialNumber || '',
    Language: payload?.language || '',
    SubmittedAt: payload?.submittedAt || new Date().toISOString(),
    AdditionalProducts: JSON.stringify(payload?.additionalProducts || []),
    Attachments: files
  }
}];
